"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[3786],{1938(e,t,o){o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>l,frontMatter:()=>a,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-15","title":"Discourses \u2014 Book 2, Chapter 15","description":"Book 2 \u2014 Chapter 15","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-15.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-15","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-15","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":16,"frontMatter":{"sidebar_position":16,"title":"Discourses \u2014 Book 2, Chapter 15","sidebar_label":"Book 2, Ch. 15"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 14","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-14"},"next":{"title":"Book 2, Ch. 16","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-16"}}');var i=o(4848),n=o(8453);const a={sidebar_position:16,title:"Discourses \u2014 Book 2, Chapter 15",sidebar_label:"Book 2, Ch. 15"},r="Discourses",h={},d=[{value:"Book 2 \u2014 Chapter 15",id:"book-2--chapter-15",level:2},{value:"On Those Who Cling Stubbornly To Their Judgements",id:"on-those-who-cling-stubbornly-to-their-judgements",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function c(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,n.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)("div",{style:{textAlign:"center"},children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,i.jsx)(t.h2,{id:"book-2--chapter-15",children:"Book 2 \u2014 Chapter 15"}),(0,i.jsx)(t.h3,{id:"on-those-who-cling-stubbornly-to-their-judgements",children:"On Those Who Cling Stubbornly To Their Judgements"})]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,i.jsxs)(o,{open:!0,children:[(0,i.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.p,{children:"A corrective against misreading Stoic steadfastness. Firmness is only a virtue if what you're firm about is sound. A man who has decided to starve himself and refuses to reconsider isn't displaying philosophical constancy \u2014 he's displaying rigidity that Epictetus has to work hard to dislodge."}),(0,i.jsx)(t.p,{children:'The distinction: firmness of health versus firmness of madness. Madmen are the most stubborn of all; that doesn\'t make their stubbornness admirable. A weak mind that happens to be energetic in its weakness is the hardest case \u2014 the flux runs now here, now there, but when it has force behind it, it becomes unreachable. The chapter is partly a reminder that "I have decided" is not an argument, and partly a warning that misapplied philosophical vocabulary can armor genuine pathology.'})]}),"\n",(0,i.jsxs)(o,{open:!0,children:[(0,i.jsx)("summary",{children:"Text"}),(0,i.jsx)(t.h2,{id:"text",children:"Text"}),(0,i.jsx)(t.p,{children:"THERE are some who when they hear these precepts--that a man must be steadfast, and that the will is by nature a free thing and not subject to compulsion, whereas all else is subject to hindrance and compulsion, being in bondage and dependence--imagine that they must abide without swerving by every judgement that they have formed. No--first of all the judgement arrived at must be sound."}),(0,i.jsx)(t.p,{children:"For I would have the body firmly braced, but it must be the firmness of health and good condition; if you show me that you have the firmness of a madman and boast of that, I shall say to you, 'Look, man, for some one to cure you.' This is not firmness, but the opposite."}),(0,i.jsx)(t.p,{children:"Let me describe another state of mind to be found in those who hear these precepts amiss. A friend of mine, for instance, determined for no reason to starve himself. I learnt of it when he was in the third day of his fasting, and went and asked him what had happened."}),(0,i.jsx)(t.p,{children:"'I have decided', said he."}),(0,i.jsx)(t.p,{children:"Yes, but, for all that, say what it was that persuaded you; for if"}),(0,i.jsx)(t.p,{children:"your decision was right, here we are at your side ready to help you to leave this life, but, if your decision was against reason, then change your mind."}),(0,i.jsx)(t.p,{children:"'A man must abide by his decisions.'"}),(0,i.jsx)(t.p,{children:"What are you doing, man? Not all decisions, but right decisions. For instance, if you were convinced at the moment that it was right, abide by that opinion if you think fit, and do not change it, but say, 'one must abide by one's decisions.'"}),(0,i.jsx)(t.p,{children:"Will you not lay this foundation to begin with--that is, examine your decision and see whether it is sound or unsound, and then afterwards build on it your firmness and unshaken resolve? But if you lay a rotten and crumbling foundation you will not be able to build even a tiny building; the more courses and the stronger that you lay upon it the quicker will it collapse. You are removing from life without any reason our familiar friend, our fellow citizen in the great City and the small, and then, though you are guilty of murder and of killing one who has done no wrong, you say, 'I must abide by my decisions.' If perchance it occurred to you to kill me, would you be bound to abide by your decisions?"}),(0,i.jsx)(t.p,{children:"Well, I had much ado to persuade that friend to change his mind. But it is impossible to move some of the men of to-day, so that I think that I know now what I did not know before, the meaning of the familiar saying, 'A fool is not to be persuaded nor broken of his folly.' May it never be my lot to have for friend a wise fool: nothing is more difficult to handle."}),(0,i.jsx)(t.p,{children:"'I have decided.'"}),(0,i.jsx)(t.p,{children:"So have the madmen, but the more firmly they persist in false judgements the more hellebore  do they require. Will you not act as the sick man should, and call in the physician? As he says, 'I am sick, master; help me: consider what I ought to do, it is for me to obey you', so you should say, 'I do not know what I ought to do, but I have come to learn.' Oh no, you say: 'Talk to me about other things; this I have decided.' Other things indeed! What is greater or more to your advantage than that you should be convinced that it is not sufficient to have decided and to refuse all change of mind? This is the firmness of madness, not of health."}),(0,i.jsx)(t.p,{children:"'If you force me to this, I would fain die.'"}),(0,i.jsx)(t.p,{children:"Why, man, what has happened?"}),(0,i.jsx)(t.p,{children:"'I have decided.'"}),(0,i.jsx)(t.p,{children:"Lucky for me that you have not decided to kill me."}),(0,i.jsx)(t.p,{children:"'I do not take fees.'"}),(0,i.jsx)(t.p,{children:"Why?"}),(0,i.jsx)(t.p,{children:"'I have decided.'"}),(0,i.jsx)(t.p,{children:"Let me tell you that the same energy with which you now refuse to take fees may incline you one day (what is to prevent it?) to take them and to say again, 'I have decided.'"}),(0,i.jsx)(t.p,{children:"Just as in an ailing body, which suffers from a flux, the flux inclines now to this part and now to that, so it is with a weak mind: no one can tell which way it sways, but when this swaying and drift has energy to back it, then the mischief becomes past help and remedy."})]})]})}function l(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},8453(e,t,o){o.d(t,{R:()=>a,x:()=>r});var s=o(6540);const i={},n=s.createContext(i);function a(e){const t=s.useContext(n);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),s.createElement(n.Provider,{value:t},e.children)}}}]);